Here's how to write modern MSTest tests for `DataFetcher` covering async patterns, timeouts, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello world"),
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ErrorStatus_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act & Assert — HttpClient throws OperationCanceledException (or derived
        // TaskCanceledException) when the token is already canceled.
        await Assert.ThrowsAsync<OperationCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_WithTimeout_CompletesWithinLimit()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("fast response"),
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act — pass TestContext.CancellationToken so the [Timeout] can
        // cooperatively cancel the call if it runs too long.
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("fast response", result);
    }

    [TestMethod]
    [DataRow("https://example.com/a", "response-a")]
    [DataRow("https://example.com/b", "response-b")]
    public async Task FetchAsync_MultipleUrls_ReturnsExpectedContent(
        string url, string expected)
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent(expected),
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync(url);

        // Assert
        Assert.AreEqual(expected, result);
    }

    /// <summary>
    /// Minimal HttpMessageHandler stub that returns a canned response.
    /// </summary>
    private sealed class FakeHandler(HttpResponseMessage response) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Sealed class** | `public sealed class` for performance |
| **Constructor-injected TestContext** | Enables `readonly` field, no nullable quirks |
| **Async tests** | `async Task` return type, `await` throughout |
| **Timeout + cooperative cancel** | `[Timeout(5000)]` + `_testContext.CancellationToken` passed into the method under test |
| **Cancellation test** | Pre-cancel a `CancellationTokenSource`, assert `OperationCanceledException` |
| **Exception assertion** | `Assert.ThrowsExactlyAsync` instead of `[ExpectedException]` |
| **Data-driven** | `[DataRow]` for parameterized cases |
| **No mocking library needed** | A small `FakeHandler` stubs `HttpClient` at the transport level |

The `FakeHandler` calls `cancellationToken.ThrowIfCancellationRequested()` so the cancellation test works realistically. For the timeout test, passing `TestContext.CancellationToken` lets MSTest's `[Timeout]` cooperatively cancel the call if it exceeds the limit.
